var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저더러…… 에델을 막으라고요?","JPN":"私に……エデルを止めろと？","ENG":"You want me... to stop Edel?","TWN":"讓我……阻止艾瑟兒？"},"stage":{"bg":"ESPR2_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그게 지금 말이 된다고 생각해요…?","JPN":"そんなことが、できるとお思いですか……？","ENG":"You cannot be serious...!","TWN":"你覺得這像話嗎……？"},"stage":{"bg":"ESPR2_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제 꼴을 보세요… 이런 한심한 인간이 뭘 할 수 있는데요…","JPN":"今の私を見てください……こんな情けない人間に、何ができるというのですか……？","ENG":"I mean, look at me... What can a pathetic girl like me do...?","TWN":"看看我這副樣子……我這種可憐人能做什麼……"},"stage":{"bg":"ESPR2_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제 뭘 믿고, 그런 말을……!","JPN":"私の何を信じて、そのような……！","ENG":"How can you say that when–!","TWN":"我憑什麼，相信這種話……！"},"stage":{"bg":"ESPR2_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네를 믿고 하는 부탁이라네.","JPN":"君を信じての頼みだ。","ENG":"I'm asking because I trust you.","TWN":"找你幫忙，是因為我相信你。"},"stage":{"bg":"ESPR2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"인간으로서, 이성을 견지하고 학회와 마주했던 자네 말이야.","JPN":"人間として、理性を堅持し学会と向かい合った君を。","ENG":"You, a human being who stood by reason and faced the Society.","TWN":"相信身為人類仍能堅守本心面對學會的你。"},"stage":{"bg":"ESPR2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그딴 건 아무짝에도 쓸모없었어요……!","JPN":"そんなものは何の役にも立ちませんでしたわ……！","ENG":"And look where that got me...!","TWN":"這些東西一點用都沒有……！"},"stage":{"bg":"ESPR2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아무리 그럴싸한 말도… 아무도 들어 주지 않으면 무슨 소용이냐고요….","JPN":"いくらそれらしい言葉も……聞いてくれる人がいないと無駄なのです……","ENG":"No matter how hard I try to convince them... What use is it when they are not willing to listen?","TWN":"就算再怎麼有道理的話……說出來沒有人聽，又有什麼用……"},"stage":{"bg":"ESPR2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"맥크레디 양은 정치로 사람들을 움직여 온 사람이었나?","JPN":"マクレディー君は政治で人々を動かしてきた人だったか？","ENG":"Regina, were you one to convince people with politics?","TWN":"麥克蕾蒂是靠政治打動人們的嗎？"},"stage":{"bg":"ESPR2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"에델의 계획을 막으려고 프리드웬까지 끌어들였다고요……!","JPN":"エデルの計画を止めるために、プリドウェンまで引き入れました……！","ENG":"I even got the Prydwen Institution involved to stop Edel...!","TWN":"為了阻止艾瑟兒的計畫，我甚至把普利多溫牽扯進來了……！"},"stage":{"bg":"ESPR2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아니면 지략과 묘수로 난관을 타개해 왔나?","JPN":"それとも知略や妙策で難関を乗り越えてきたのか？","ENG":"Or, have you overcome difficulties by being resourceful and cunning?","TWN":"還是說你是用智謀和妙計渡過難關的？"},"stage":{"bg":"ESPR2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제 힘으로는 에델을 멈출 수 없어요… 학회원들이 득실거릴 텐데 저 혼자 어떻게…!","JPN":"私の力ではエデルを止めることはできません……学会員がうじゃうじゃいるはずなのに、私一人でどうやって……！","ENG":"I could not stop Edel alone... How am I supposed to face all of the Society by myself...?!","TWN":"靠我的力量阻止不了艾瑟兒……學會成員那麼多，我一個人怎麼……！"},"stage":{"bg":"ESPR2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"여태까지 힘의 논리로 적을 쓰러뜨렸던 건가?","JPN":"今まで力の論理で敵を倒してきたのか？","ENG":"Have you dominated your enemies using the overwhelming force?","TWN":"難道你以前都是用力量的邏輯打倒敵人的嗎？"},"stage":{"bg":"ESPR2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그만해!!","JPN":"やめて！！","ENG":"STOP IT!!","TWN":"不要再說了！！"},"stage":{"bg":"ESPR2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그럼 어떡할지 답을 줘! 정답을 알고 있으면서 왜!!","JPN":"それじゃあ、どうするか答えをちょうだい！　正解をわかっているくせになんで！！","ENG":"Then tell me what I should do if you already know the answer!!","TWN":"那你告訴我，我該怎麼辦！你明明知道答案，為什麼不告訴我！！"},"stage":{"bg":"ESPR2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그게 자네가 탐식자에게 맞설 수 있는 유일한 수단이니까.","JPN":"それが君が貪食者に立ち向かえる唯一の手だからだ。","ENG":"Because that's the only weapon you have to fight against the Devourer.","TWN":"因為這是你能對抗貪食者的唯一方法。"},"stage":{"bg":"ESPR2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ESPR2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"맥크레디 양, 실패를 겪고 꺾이는 건 사람인 이상 당연해.","JPN":"マクレディー君、失敗を経験してくじけてしまうのは、人間である以上当然のことだ。","ENG":"Regina, it's natural to get discouraged when you fail.","TWN":"麥克蕾蒂，只要是人，必然會經歷失敗和挫折。"},"stage":{"bg":"ESPR2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"포기해도 좋아.","JPN":"あきらめてもよい。","ENG":"It's okay to give up.","TWN":"放棄也沒關係。"},"stage":{"bg":"ESPR2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네를 탓할 자격은 아무에게도 없다네. 자네는 최선을 다해 왔어.","JPN":"誰にも君を責める資格はない。君は最善を尽くしてきた。","ENG":"There is no one who can blame you for that. You have always done your best.","TWN":"任何人都沒有資格責怪你。因為你已經盡力了。"},"stage":{"bg":"ESPR2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 포기하기 전에, 자네가 왜 학회에 뛰어들었는지 다시 한 번 생각해 보게.","JPN":"だがあきらめる前に、君がどうして学会に入ったかをもう一度思い出してくれたまえ。","ENG":"However, before you do, I want you to think about why you stood up against the Society in the first place.","TWN":"但是放棄之前，請你再好好想想，當初你為什麼會加入學會。"},"stage":{"bg":"ESPR2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네는 분명 답을 찾을 수 있을 거야.","JPN":"君ならきっと答えを見つけられるはずだ。","ENG":"Then, I'm sure you'll find the answer you're looking for.","TWN":"你一定能找到答案。"},"stage":{"bg":"ESPR2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저는……","JPN":"私は……","ENG":"I...","TWN":"我……"},"stage":{"bg":"ESPR2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"사장님이랑 오붓한 시간 잘 보냈어, 레지나?","JPN":"社長との時間は楽しかった？　レジーナ。","ENG":"How was your date with Boss, Regina?","TWN":"和老闆度過了愉快的時光嗎，蕾佳娜？"},"stage":{"bg":"ESPR2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"어서 일어나는 게 좋을걸? 여기 계속 있으면 터진 피냐타 꼴 난다?","JPN":"早く起きた方がいいかもね。ずっとここにいると、割れたピニャータみたいになるよ？","ENG":"You'd better get up now. If we stay here any longer, we're going to look like exploded piñatas.","TWN":"你還是快點站起來吧？繼續留在這裡，會被打爆的。"},"stage":{"bg":"ESPR2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"침식체들이 그렇게나 많았는데…… 왜 뛰어든 거예요?","JPN":"あれほど侵食体がいたのに……どうして飛び込んだのですか？","ENG":"There were so many C.O.s here... but why did you decide to come looking for me?","TWN":"那麼多侵蝕體……你為什麼要衝進來？"},"stage":{"bg":"ESPR2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"그야 당연히 신나게 쏘고 싶어서지~","JPN":"そりゃもちろん、楽しく撃ちまくりたかったからね～","ENG":"Well, so I can shoot as many of them as I want, silly!","TWN":"當然是因為我想痛快地開槍了～"},"stage":{"bg":"ESPR2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……한결같네요. 저랑 다르게.","JPN":"……あなたは変わりませんね。私とは違って。","ENG":"You never change, do you? Unlike me...","TWN":"……你真是始終如一，和我不一樣。"},"stage":{"bg":"ESPR2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"부축해 주세요. 혼자선 못 일어나겠어요.","JPN":"手を貸してください。一人では起き上がれません。","ENG":"Could you help me? I cannot seem to get up on my own.","TWN":"扶我一把，我自己站不起來了。"},"stage":{"bg":"ESPR2_05","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님…! 무사하셨군요!","JPN":"副学会長様……！　ご無事でしたか！","ENG":"Vice President! Thank goodness you made it!","TWN":"副學會長……！你沒事吧！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"네. 저 때문에 걱정이 많았죠. 미안해요, 실키.","JPN":"はい。私のせいで心配をかけてしまいました。すみません、シルキー。","ENG":"Yes. I apologize for causing you so much concern, Sylkie.","TWN":"沒事，害你為我擔心了，對不起，思琪。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"그런데… 혹시 우신 거에요? 얼굴에 눈물 자국이 있어요.","JPN":"あの……もしかして泣かれてたんですか？　顔に涙の跡が残ってます。","ENG":"But, um... were you crying? I can see tear marks running down your cheek.","TWN":"不過……你這是哭了嗎？怎麼臉上有淚痕。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아, 아니에요. 그런 거….","JPN":"ち、違います。そんな……","ENG":"N-no. Those are not tear marks at all...","TWN":"沒…沒有，沒那回事……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"모른 척 하게, 실키 양. 어른들도 가끔은 울고 싶을 때가 있다네.","JPN":"知らんふりをしてあげたまえ、シルキー君。大人もたまには泣きたくなる時があるのだ。","ENG":"Pretend you didn't see them, Sylkie. Sometimes, adults also want to cry.","TWN":"假裝不知道吧，思琪。大人偶爾也會有想哭的時候。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"정말요?","JPN":"そうなんですか？","ENG":"Really?","TWN":"真的嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"조, 조용히 하세요! 안 울었다니까요!","JPN":"し、静かにしてください！　泣いてませんって！","ENG":"Y-you shush that mouth of yours! I said I did not cry!","TWN":"你…你閉嘴！我才沒哭！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그냥…. 으음, 하소연 좀 했을 뿐입니다. 어린애도 아니고 말이죠.","JPN":"ただ……うーん、愚痴を言っていただけです。子どもではありませんし。","ENG":"I, um... just need to get things off my chest. I am not a child, you know.","TWN":"就是……呃嗯，我就是發發牢騷。我又不是小孩子。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"그런데 사장님이라고 했지? 많이 망가진 것 같네.","JPN":"ていうか、社長だっけ？　すごいボロボロだね。","ENG":"Err, Boss, was it? You seem badly damaged.","TWN":"不過你叫老闆是吧？好像身體損壞很嚴重呢。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"겁없이 균열로 뛰어든 자네 덕분이지. 모처럼 공들여 만든 역작이었건만….","JPN":"大胆に亀裂に飛び込んだ君のおかげさ。特別丹精を込めて作った力作だったのだが……","ENG":"Thanks to your impeccable judgment of jumping into the rift. This was a masterpiece that I worked hard to make...","TWN":"還不是因為你大膽跳入裂縫，我才會變成這樣。這可是我花了不少功夫做出來的傑作……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"그냥 상자 얹어 놓은 것처럼 생겼는데?","JPN":"ただ箱を乗せたような格好だけどね。","ENG":"But you just look like a couple of boxes stacked up on one another.","TWN":"可外形就像隨便和一個箱子拼湊在一起啊？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"크흠, 예술을 모르는군. 이 기능미 넘치는 조형이 하루 아침에 나올 것 같나?","JPN":"コホン、芸術を理解していないな。この機能美溢れる造形は一晩に作られたものではないのだぞ。","ENG":"Ahem! You clearly don't know art. Do you think that this kind of functional sculpture can be made in just a day?","TWN":"咳呵，那是因為你不懂藝術。你以為這種充滿功能美的造型，一夜之間就能做出來嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"포기하세요, 사장님. 리벳과 말씨름해 봐야 소용없습니다.","JPN":"あきらめてください、社長。リベットと口喧嘩をしても無駄ですわ。","ENG":"Why bother, Boss? There is no point in arguing with Rivet.","TWN":"放棄吧，老闆。你跟里維鬥嘴也沒用。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그보다…… 큭……!","JPN":"それより……くっ……！","ENG":"Besides... Ngh!","TWN":"話說回來……咳……！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"조심하세요, 부학회장님. 제가 부축해 드릴게요.","JPN":"気をつけてください、副学会長様。私がお手伝いします。","ENG":"Careful, ma'am! Here, I'll support you.","TWN":"你小心點，副學會長，我扶著你。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아, 네. 고마워요, 실키.","JPN":"あ、はい。ありがとうございます、シルキー。","ENG":"Oh, thank you, Sylkie.","TWN":"啊，好，謝謝你，思琪。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"리벳, 다른 침식체들 눈에 띄기 전에 숨을 곳을 찾아야겠어요.","JPN":"リベット、他の侵食体にバレる前に隠れられるところを探さないといけません。","ENG":"Rivet, we must find a place to hide before the other C.O.s see us.","TWN":"里維，在被其他侵蝕體發現之前，我們得找個藏身之處。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당신이라면 안전한 장소를 찾을 수 있겠죠?","JPN":"あなたなら安全な場所を探せますね？","ENG":"I believe you can find us a safe hideout, right?","TWN":"你能找到安全的地方吧？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"으응? 침식체들이 알아서 환영식까지 열어 준다는데 내가 왜?","JPN":"ううん？　侵食体自ら歓迎してくれるって言うのに、なんでアタシが？","ENG":"Hmm? Why would I when the C.O.s are giving us a welcome party?","TWN":"呃嗯？侵蝕體們願意為我們舉辦歡迎儀式，我們為什麼要藏？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"화려하게 저지르고 싶으면 큰물에서 놀아야죠.","JPN":"派手に遊びたいのなら、大きい舞台が必要です。","ENG":"Why catch small fry when you can hunt bigger fish?","TWN":"如果想要戰鬥華麗，就要把事情搞大。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저를 믿고 따라오세요. 그럼 원없이 날뛸 수 있게 해 드리겠습니다.","JPN":"私を信じて言うとおりにしてください。思いっきり暴れられる場所を用意しますわ。","ENG":"Trust and follow me. I will let you wreak havoc as much as you want.","TWN":"相信我就跟我來吧。我會讓你們玩個痛快的。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"고용주님이 그렇게 말씀하시면 어쩔 수 없나~","JPN":"クライアントがそう言うなら仕方ないか～","ENG":"Well, you hired me, so I guess I don't have much of a choice!","TWN":"既然雇主都這麼說了，那就沒辦法了呢～"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"여기서 좀 쉬다가 천천히 따라와. 찾으면 신호탄을 쏠 테니까.","JPN":"ここでちょっと休んでからゆっくりついて来てよ。見つけたら信号弾を打つから。","ENG":"Rest here and catch up to me later. I'll send a signal once I find a place.","TWN":"你們在這裡休息一下再慢慢跟上。找到合適的地方後我會發訊號彈。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님, 저…… 해선 안 될 말인 것 같지만요.","JPN":"副学会長様、あの……言ってはいけない言葉だとは思いますが。","ENG":"Ms. Vice President... forgive me for asking, but...","TWN":"副學會長，我……有句話不知道該不該說。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"붙잡히셨을 때보다 안색이 좋아 보이세요. 사장님이랑 무슨 얘기를 나누신 거예요?","JPN":"捕まっていた時より顔色がよくなっているように見えます。社長とどんな話をされたんですか？","ENG":"You look paler than when you got caught. What did you talk about with Boss?","TWN":"比起被抓的時候，你的臉色好了很多。是因為和老闆聊了什麼嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"글쎄요. 잘은 몰라도 잔뜩 도발만 당한 것 같은데요.","JPN":"さあ。よくわかりませんけど、ものすごく挑発されたような気がしますわ。","ENG":"I am not really sure. I feel like all he did was taunt me.","TWN":"這個嘛，雖然不太清楚，但是我好像受到了嚴重的挑釁。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"도와 달라고 왔다더니, 수수께끼 같은 문제나 던지고 말이죠.","JPN":"助けを求めるために来たとか言っておいて、謎みたいな問題を投げかけて。","ENG":"I asked him to help me, and he kept throwing these riddles at me.","TWN":"我說讓他幫幫我，結果他卻丟給我一個謎題。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"크흠. 원래 의욕을 불어넣는 데에는 즉효약이지.","JPN":"コホン。やる気を出させるには即効薬なのだぞ。","ENG":"Ahem! Well, that is the best way to motivate someone after all.","TWN":"咳嗯，挑釁本來就是很棒的激將法。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"뭐, 그렇겠죠.","JPN":"まあ、そうでしょうね。","ENG":"I suppose so.","TWN":"嗯，是啊。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그래도 덕분에…….","JPN":"でも、おかげで……","ENG":"But thanks to you...","TWN":"不過多虧了你……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"조금 더 해 봐야겠다는 생각이 들었으니까요.","JPN":"もう少しやってみようと思うようになりましたから。","ENG":"I think I will try a little bit more.","TWN":"我又有應該再嘗試一下的想法了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};